module top_module(
	input [7:0] XOR_A, B,
	output reg [7:0] Out6
);always@(XOR_A or B)
	begin
		Out6[0] <= ~(XOR_A[0] & B[0]);
		Out6[1] <= ~(XOR_A[1] & B[1]);
		Out6[2] <= ~(XOR_A[2] & B[2]);
		Out6[3] <= ~(XOR_A[3] & B[3]);
		Out6[4] <= ~(XOR_A[4] & B[4]);
		Out6[5] <= ~(XOR_A[5] & B[5]);
		Out6[6] <= ~(XOR_A[6] & B[6]);
		Out6[7] <= ~(XOR_A[7] & B[7]);
	end

endmodule
